fixed_code:
use std::marker::PhantomData;

struct Container<'a, T: 'a> {
    data: &'a T,
    marker: PhantomData<&'a T>,
}

impl<'a, T: 'a> Container<'a, T> {
    fn new(data: &'a T) -> Self {
        Self { data, marker: PhantomData }
    }
}

fn main() {
    let x = 42;
    let y: &i32 = &x;
    let container = Container::new(y);
    println!("{}", if *container.data < i32::MAX / 10 { container.data * 10 } else { 999 });
}
